def cache_decorator(seconds):
    def decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            cache_key = f"{str(func.__name__)}:{str(args)}:{str(kwargs)}"
            result = redis_store.get(cache_key)
